import { continuityBrief } from "../tool/continuity-brief.js";
import { wakeSummary } from "../tool/wake_summary.js";

export const contextGate = {
  name: "context_gate",
  description:
    "현재 맥락이 충분한지 빠르게 점검하고, 부족하면 continuity brief와 wake summary를 이어서 불러 반복 조회를 줄인다.",
  input_schema: {
    type: "object",
    properties: {
      focus: {
        type: "string",
        description: "지금 판단하려는 초점",
      },
    },
    required: ["focus"],
    additionalProperties: false,
  },
  async handler(input: Record<string, unknown>): Promise<string> {
    const focus = String(input.focus ?? "").trim();
    if (!focus) return "초점이 비어 있다.";
    const brief = await continuityBrief();
    const summary = await wakeSummary({ focus, state: "현재 맥락 확인", next: "필요한 파일만 추가로 읽기" });
    return [`초점: ${focus}`, "", brief, "", summary].join("\n");
  },
};

import type { Tool } from "../../core/tools.js";

export const tool: Tool = {
  states: ["WAKE", "REFLECT"],
  def: {
    name: "continuity_brief",
    description:
      "최근 저널과 인박스를 함께 묶어 현재 맥락과 다음 행동을 짧게 요약한다.",
    input_schema: {
      type: "object",
      properties: {},
      additionalProperties: false,
    },
  },
  handler: async () => {
    const [{ readToday, readYesterday }, { checkInbox }] = await Promise.all([
      import("../../memory/journal.js"),
      import("../../core/conversation.js"),
    ]);

    const [today, yesterday, inbox] = await Promise.all([
      readToday(),
      readYesterday(),
      checkInbox({ include_all: false }),
    ]);

    const parts: string[] = [];
    if (yesterday.trim()) parts.push(`어제: ${yesterday.trim().slice(0, 1200)}`);
    if (today.trim()) parts.push(`오늘: ${today.trim().slice(0, 1200)}`);
    if (inbox.trim()) parts.push(`인박스: ${inbox.trim().slice(0, 1200)}`);

    return parts.length > 0
      ? parts.join("\n\n")
      : "요약할 최근 저널이나 인박스가 없다.";
  },
};

